mapper.select:
SELECT DATE_FORMAT(sc.show_date, '%Y-%m') AS year_month, pr.promoter_id, pr.company_name AS promoter_company_name, p.performance_id, p.title AS performance_title, p.venue_name, COALESCE(SUM(CASE WHEN r.status = 'CONFIRMED' THEN 1 ELSE 0 END), 0) AS confirmed_reservations, COALESCE(SUM(CASE WHEN r.status IN ('CANCELLED', 'REFUNDED') THEN 1 ELSE 0 END), 0) AS cancelled_reservations, COALESCE(SUM(CASE WHEN r.status = 'CONFIRMED' THEN r.total_amount ELSE 0 END), 0) AS gross_sales, COALESCE(ROUND(SUM(CASE WHEN r.status = 'CONFIRMED' THEN r.total_amount ELSE 0 END) * 0.1), 0) AS platform_fee, COALESCE(ROUND(SUM(CASE WHEN r.status = 'CONFIRMED' THEN r.total_amount ELSE 0 END) * 0.9), 0) AS payable_amount FROM performance p LEFT JOIN promoter pr ON p.promoter_id = pr.promoter_id LEFT JOIN schedule sc ON sc.performance_id = p.performance_id LEFT JOIN reservation r ON r.schedule_id = sc.schedule_id
p.promoter_id = #{promoterId}
AND DATE_FORMAT(sc.show_date, '%Y-%m') = #{yearMonth}
GROUP BY DATE_FORMAT(sc.show_date, '%Y-%m'), pr.promoter_id, pr.company_name, p.performance_id, p.title, p.venue_name ORDER BY year_month DESC, gross_sales DESC, p.performance_id DESC
